/**
 * @summary Process natural language query intelligently
 */
export const getProcessQueryUrl = () => {
  return `/api/query-process`;
};

export const processQuery = async (
  queryProcessBody: QueryProcessBody,
  options?: RequestInit,
): Promise<QueryProcessResponse> => {
  return customFetch<QueryProcessResponse>(getProcessQueryUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(queryProcessBody),
  });
};

export const getProcessQueryMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof processQuery>>,
    TError,
    { data: BodyType<QueryProcessBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof processQuery>>,
  TError,
  { data: BodyType<QueryProcessBody> },
  TContext
> => {
  const mutationKey = ["processQuery"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof processQuery>>,
    { data: BodyType<QueryProcessBody> }
  > = (props) => {
    const { data } = props ?? {};

    return processQuery(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type ProcessQueryMutationResult = NonNullable<
  Awaited<ReturnType<typeof processQuery>>
>;
export type ProcessQueryMutationBody = BodyType<QueryProcessBody>;
export type ProcessQueryMutationError = ErrorType<unknown>;

/**
 * @summary Process natural language query intelligently
 */
export const useProcessQuery = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof processQuery>>,
    TError,
    { data: BodyType<QueryProcessBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof processQuery>>,
  TError,
  { data: BodyType<QueryProcessBody> },
  TContext
> => {
  return useMutation(getProcessQueryMutationOptions(options));
};

